#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_LINE 512

void trim_newline(char *s) {
    size_t len = strlen(s);
    if (len && s[len-1] == '\n') s[len-1] = '\0';
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; if (scanf("%d", &N) != 1) return 0;
        getchar(); // consume endline after N
        char **logs = (char**)malloc(N * sizeof(char*));
        for (int i = 0; i < N; ++i) {
            logs[i] = (char*)malloc(MAX_LINE);
            fgets(logs[i], MAX_LINE, stdin);
            trim_newline(logs[i]);
        }
        char filterLine[MAX_LINE];
        fgets(filterLine, MAX_LINE, stdin);
        trim_newline(filterLine);
        char filterLevel[20] = "", filterKeyword[60] = "";
        int parts = sscanf(filterLine, "%19s %59s", filterLevel, filterKeyword);
        int printed = 0;
        for (int i = 0; i < N; ++i) {
            char level[20], keyword[60];
            if (sscanf(logs[i], "%19s %59[^:]:", level, keyword) != 2) continue;
            int match = 0;
            if (parts == 2) {
                if (strcmp(level, filterLevel) == 0 && strcmp(keyword, filterKeyword) == 0) match = 1;
            } else if (parts == 1) {
                if (strcmp(level, filterLevel) == 0) match = 1;
            }
            if (match) {
                printf("%s\n", logs[i]);
                printed = 1;
            }
        }
        if (!printed) printf("No logs found.\n");
        if (T) printf("\n"); // blank line between test cases
        for (int i = 0; i < N; ++i) free(logs[i]);
        free(logs);
    }
    return 0;
}

