import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            List<String> logs = new ArrayList<>();
            for (int i = 0; i < N; i++) logs.add(br.readLine());
            String filterLine = br.readLine();
            String[] filterParts = filterLine.trim().split(" ");
            String filterLevel = filterParts[0];
            String filterKeyword = filterParts.length > 1 ? filterParts[1] : "";
            boolean any = false;
            for (String log : logs) {
                int colon = log.indexOf(':');
                if (colon == -1) continue;
                String before = log.substring(0, colon).trim();
                String[] parts = before.split(" ");
                if (parts.length < 2) continue;
                String level = parts[0];
                String keyword = parts[1];
                boolean match = false;
                if (filterKeyword.isEmpty()) {
                    if (level.equals(filterLevel)) match = true;
                } else {
                    if (level.equals(filterLevel) && keyword.equals(filterKeyword)) match = true;
                }
                if (match) {
                    out.append(log).append('\n');
                    any = true;
                }
            }
            if (!any) out.append("No logs found.").append('\n');
            if (tc != T - 1) out.append('\n'); // blank line between test cases
        }
        System.out.print(out.toString());
    }
}

