import sys

def main():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out = []
    for tc in range(T):
        N = int(next(it))
        logs = [next(it) for _ in range(N)]
        filter_line = next(it).strip()
        parts = filter_line.split()
        filter_level = parts[0]
        filter_keyword = parts[1] if len(parts) > 1 else ''
        any_match = False
        for log in logs:
            if ':' not in log:
                continue
            before, _ = log.split(':', 1)
            tokens = before.strip().split()
            if len(tokens) < 2:
                continue
            level, keyword = tokens[0], tokens[1]
            if filter_keyword:
                if level == filter_level and keyword == filter_keyword:
                    out.append(log)
                    any_match = True
            else:
                if level == filter_level:
                    out.append(log)
                    any_match = True
        if not any_match:
            out.append('No logs found.')
        if tc != T - 1:
            out.append('')  # blank line between test cases
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

